import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"🥈 白銀供給面深度分析","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_供給面分析.md","filePath":"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_供給面分析.md"}'),i={name:"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_供給面分析.md"};function n(d,t,s,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🥈-白銀供給面深度分析" tabindex="-1">🥈 白銀供給面深度分析 <a class="header-anchor" href="#🥈-白銀供給面深度分析" aria-label="Permalink to &quot;🥈 白銀供給面深度分析&quot;">​</a></h1><blockquote><p><strong>最後更新</strong>：2026-06-11 <strong>資料來源</strong>：World Silver Survey 2026, S&amp;P Global, CRU, USGS</p></blockquote><hr><h2 id="一、全球白銀供給總覽" tabindex="-1">一、全球白銀供給總覽 <a class="header-anchor" href="#一、全球白銀供給總覽" aria-label="Permalink to &quot;一、全球白銀供給總覽&quot;">​</a></h2><p>2026 年全球白銀總供給預計 <strong>10.5 億盎司</strong>，為十年來最高水平（+1.5% YoY）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">供給來源</th><th style="text-align:right;">2024A</th><th style="text-align:right;">2025A</th><th style="text-align:right;">2026E</th><th style="text-align:left;">變化</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>礦產銀</strong></td><td style="text-align:right;">819.7 Moz</td><td style="text-align:right;">~840 Moz</td><td style="text-align:right;">820 Moz</td><td style="text-align:left;">+1% (2026E)</td></tr><tr><td style="text-align:left;"><strong>回收銀</strong></td><td style="text-align:right;">187 Moz</td><td style="text-align:right;">~195 Moz</td><td style="text-align:right;">~210 Moz</td><td style="text-align:left;"><strong>+7%</strong></td></tr><tr><td style="text-align:left;"><strong>政府拋售</strong></td><td style="text-align:right;">微量</td><td style="text-align:right;">微量</td><td style="text-align:right;">微量</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>總供給</strong></td><td style="text-align:right;">~1,007 Moz</td><td style="text-align:right;">~1,035 Moz</td><td style="text-align:right;"><strong>~1,050 Moz</strong></td><td style="text-align:left;"><strong>+1.5%</strong></td></tr></tbody></table><hr><h2 id="二、礦產供給-佔-78" tabindex="-1">二、礦產供給（佔 78%） <a class="header-anchor" href="#二、礦產供給-佔-78" aria-label="Permalink to &quot;二、礦產供給（佔 78%）&quot;">​</a></h2><h3 id="_2-1-主要產銀國" tabindex="-1">2.1 主要產銀國 <a class="header-anchor" href="#_2-1-主要產銀國" aria-label="Permalink to &quot;2.1 主要產銀國&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th style="text-align:left;">國家</th><th style="text-align:right;">年產量</th><th style="text-align:center;">佔全球</th><th style="text-align:left;">趨勢</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;"><strong>墨西哥</strong></td><td style="text-align:right;">~200 Moz</td><td style="text-align:center;">~24%</td><td style="text-align:left;">🟡 產量穩定但 Peñasquito 罷工風險</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;"><strong>中國</strong></td><td style="text-align:right;">~110 Moz</td><td style="text-align:center;">~13%</td><td style="text-align:left;">🟢 工業需求最大的同時也是主要生產國</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;"><strong>秘魯</strong></td><td style="text-align:right;">~130 Moz</td><td style="text-align:center;">~15%</td><td style="text-align:left;">🔴 能源危機（Decree 003-2026）+ 礦石品位下降</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;"><strong>玻利維亞</strong></td><td style="text-align:right;">~50 Moz</td><td style="text-align:center;">~6%</td><td style="text-align:left;">🟡 政治不穩定</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;"><strong>智利</strong></td><td style="text-align:right;">~48 Moz</td><td style="text-align:center;">~6%</td><td style="text-align:left;">🟢 銅礦副產銀</td></tr></tbody></table><blockquote><p><strong>關鍵風險</strong>：秘魯的能源危機（Emergency Decree No. 003-2026）直接影響年產約 1.3 億盎司的白銀供應，且秘魯供應中國約一半的銀精礦進口。</p></blockquote><h3 id="_2-2-銀礦類型分布" tabindex="-1">2.2 銀礦類型分布 <a class="header-anchor" href="#_2-2-銀礦類型分布" aria-label="Permalink to &quot;2.2 銀礦類型分布&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">礦種</th><th style="text-align:right;">佔比</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>鉛鋅礦副產</strong></td><td style="text-align:right;">~45%</td><td style="text-align:left;">白銀最大來源，但產量平緩</td></tr><tr><td style="text-align:left;"><strong>銀礦/金礦共生</strong></td><td style="text-align:right;">~30%</td><td style="text-align:left;">金礦副產是增長最快的來源（2025 +12% YoY）</td></tr><tr><td style="text-align:left;"><strong>銅礦副產</strong></td><td style="text-align:right;">~25%</td><td style="text-align:left;">受銅礦擴產間接帶動</td></tr></tbody></table><blockquote><p>💡 <strong>關鍵特徵</strong>：白銀僅 ~30% 來自原生銀礦，其餘 70% 為銅、鉛、鋅、金礦的<strong>副產品</strong>。這意味：</p><ul><li>白銀供給不受自身價格直接調節（主金屬開採意願決定產量）</li><li>即便銀價大漲，礦商也無法快速增產（需銅/鉛/鋅需求同步增長）</li></ul></blockquote><h3 id="_2-3-供給瓶頸" tabindex="-1">2.3 供給瓶頸 <a class="header-anchor" href="#_2-3-供給瓶頸" aria-label="Permalink to &quot;2.3 供給瓶頸&quot;">​</a></h3><ol><li><strong>礦石品位（Ore Grade）持續下降</strong>：全球主要銀礦的平均品位十年內下降 30%+</li><li><strong>礦山老化</strong>：墨西哥 Fresnillo、秘魯 Cerro de Pasco 等百年礦區逐漸枯竭</li><li><strong>新增礦山不足</strong>：高銀價雖然刺激勘探，但從發現到生產需 7-15 年</li><li><strong>ESG/政治風險</strong>：秘魯能源危機、墨西哥礦業政策不確定性</li><li><strong>用水與環境許可</strong>：礦業開發審批週期持續延長</li></ol><hr><h2 id="三、回收供給-佔-20" tabindex="-1">三、回收供給（佔 20%） <a class="header-anchor" href="#三、回收供給-佔-20" aria-label="Permalink to &quot;三、回收供給（佔 20%）&quot;">​</a></h2><ul><li>2026E 回收量預計 <strong>~2.1 億盎司</strong>，為 2012 年以來首次突破 2 億盎司</li><li><strong>+7% YoY</strong>，受高銀價激勵</li><li>主要來源： <ul><li><strong>工業廢料（電子廢棄物、催化劑）</strong>：佔比最大</li><li><strong>銀器回收</strong>：引領增長（高價激發變現）</li><li><strong>光伏板回收</strong>：目前回收率僅 ~10%，潛力大但短期無法規模化</li></ul></li></ul><p><strong>回收增長的制約</strong>：</p><ul><li>PV 模組中銀的含量極低（細線分布），回收經濟性不足</li><li>全球僅約 10% 的 EoL 光伏板進行了銀回收</li><li>專業回收設施的建設需要時間</li></ul><hr><h2 id="四、成本分析" tabindex="-1">四、成本分析 <a class="header-anchor" href="#四、成本分析" aria-label="Permalink to &quot;四、成本分析&quot;">​</a></h2><h3 id="_4-1-全球-aisc-全維持成本" tabindex="-1">4.1 全球 AISC（全維持成本） <a class="header-anchor" href="#_4-1-全球-aisc-全維持成本" aria-label="Permalink to &quot;4.1 全球 AISC（全維持成本）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:right;">全球加權平均 AISC</th><th style="text-align:left;">變化</th></tr></thead><tbody><tr><td style="text-align:center;">2024</td><td style="text-align:right;">~$18/oz</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:center;">2025</td><td style="text-align:right;">$22.59/oz</td><td style="text-align:left;">通膨 + 勞動力成本上升</td></tr><tr><td style="text-align:center;">2026E</td><td style="text-align:right;"><strong>$23.44/oz</strong></td><td style="text-align:left;"><strong>+3.8%</strong> (S&amp;P Global)</td></tr></tbody></table><h3 id="_4-2-具體礦商成本" tabindex="-1">4.2 具體礦商成本 <a class="header-anchor" href="#_4-2-具體礦商成本" aria-label="Permalink to &quot;4.2 具體礦商成本&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">礦商</th><th style="text-align:right;">2026 AISC</th><th style="text-align:left;">備註</th></tr></thead><tbody><tr><td style="text-align:left;">Pan American Silver</td><td style="text-align:right;">~$17-19/oz</td><td style="text-align:left;">最大純白銀礦商，成本最低之一</td></tr><tr><td style="text-align:left;">Endeavour Silver</td><td style="text-align:right;">$27-28/oz</td><td style="text-align:left;">Terronera 新礦投產推高成本</td></tr><tr><td style="text-align:left;">Hecla Mining</td><td style="text-align:right;">$15-16.25/oz</td><td style="text-align:left;">Keno Hill 投資期後成本改善</td></tr></tbody></table><blockquote><p>🔑 <strong>成本支撐</strong>：2026 年全球 AISC 約 <strong>$23/oz</strong>，當前銀價 $100+ 意味著礦商利潤率極高（~75%+），但供給仍無法快速擴大，驗證了供給側的結構性僵化。</p></blockquote><h3 id="_4-3-白銀-vs-其他大宗商品生產彈性" tabindex="-1">4.3 白銀 vs 其他大宗商品生產彈性 <a class="header-anchor" href="#_4-3-白銀-vs-其他大宗商品生產彈性" aria-label="Permalink to &quot;4.3 白銀 vs 其他大宗商品生產彈性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">商品</th><th style="text-align:right;">價格翻倍 → 供給增加時間</th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:left;">石油</td><td style="text-align:right;">1-3 年</td><td style="text-align:left;">頁岩油可快速增產</td></tr><tr><td style="text-align:left;">銅</td><td style="text-align:right;">5-10 年</td><td style="text-align:left;">許可審批 + 建礦週期</td></tr><tr><td style="text-align:left;">白銀</td><td style="text-align:right;"><strong>7-15 年</strong></td><td style="text-align:left;">70% 為副產品，增產受主金屬制約</td></tr></tbody></table><hr><h2 id="五、中國出口管制因素" tabindex="-1">五、中國出口管制因素 <a class="header-anchor" href="#五、中國出口管制因素" aria-label="Permalink to &quot;五、中國出口管制因素&quot;">​</a></h2><ul><li>2026 年 1 月 1 日起，中國對白銀出口實施 <strong>更嚴格的許可證制度</strong></li><li>白銀地位從一般商品提升為 <strong>「戰略性原物料」</strong> ，管制力道等同稀土</li><li>臺灣白銀高度依賴進口，近五年平均 <strong>超過 50% 依賴中國大陸</strong></li><li>中國出口管制將衝擊臺灣白銀供應鏈（電子、太陽能、PCB 產業）</li></ul><hr><h2 id="六、供給面總結" tabindex="-1">六、供給面總結 <a class="header-anchor" href="#六、供給面總結" aria-label="Permalink to &quot;六、供給面總結&quot;">​</a></h2><h3 id="🔴-供給側結構性限制" tabindex="-1">🔴 供給側結構性限制 <a class="header-anchor" href="#🔴-供給側結構性限制" aria-label="Permalink to &quot;🔴 供給側結構性限制&quot;">​</a></h3><ol><li><strong>白銀 70% 為副產品</strong> → 供給缺乏價格彈性</li><li><strong>礦石品位持續下降</strong> → 單位產量所需開採量越來越大</li><li><strong>地緣政治風險升溫</strong>（秘魯能源危機、中國稀土式出口管制）</li><li><strong>新增產能不足</strong> → 從勘探到生產需 7-15 年</li></ol><h3 id="🟢-供給增長點" tabindex="-1">🟢 供給增長點 <a class="header-anchor" href="#🟢-供給增長點" aria-label="Permalink to &quot;🟢 供給增長點&quot;">​</a></h3><ol><li><strong>金礦副產銀</strong>：2025 年 +12%，是礦產增長最快來源</li><li><strong>回收量創 14 年新高</strong>（+7%）</li><li><strong>墨西哥 Peñasquito 恢復全產能</strong></li></ol><h3 id="⚖️-供需缺口趨勢" tabindex="-1">⚖️ 供需缺口趨勢 <a class="header-anchor" href="#⚖️-供需缺口趨勢" aria-label="Permalink to &quot;⚖️ 供需缺口趨勢&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:right;">短缺量</th><th style="text-align:left;">模式</th></tr></thead><tbody><tr><td style="text-align:center;">2021</td><td style="text-align:right;">~6 Moz</td><td style="text-align:left;">首年轉為短缺</td></tr><tr><td style="text-align:center;">2023</td><td style="text-align:right;">~30 Moz</td><td style="text-align:left;">缺口加速擴大</td></tr><tr><td style="text-align:center;">2025</td><td style="text-align:right;">~40 Moz</td><td style="text-align:left;">短缺深化</td></tr><tr><td style="text-align:center;">2026E</td><td style="text-align:right;"><strong>~46-67 Moz</strong></td><td style="text-align:left;">連續第六年，史上最大</td></tr></tbody></table><blockquote><p>🔑 <strong>核心結論</strong>：白銀的供給側故事遠比需求側穩固——供給受限於副產品特性和礦山老化，在可預見的未來難以突破，這為銀價提供了長期的結構性支撐。</p></blockquote><hr><h2 id="七、資料來源" tabindex="-1">七、資料來源 <a class="header-anchor" href="#七、資料來源" aria-label="Permalink to &quot;七、資料來源&quot;">​</a></h2><ul><li>Silver Institute, World Silver Survey 2026</li><li>S&amp;P Global, Mine cost outlook 2026</li><li>CRU Investor, Mexico &amp; Peru Supply Constraints</li><li>Endeavour Silver, 2026 Guidance</li><li>Pan American Silver, 2026 Guidance</li><li>貿易雜誌，《當工業需求碰上政策博弈，白銀晉升戰略籌碼》</li><li>USGS, Mineral Commodity Summaries</li><li>Silver Institute, Silver Supply &amp; Demand</li></ul>',45)])])}const c=e(i,[["render",n]]);export{y as __pageData,c as default};
